content.content:
1	:root {
2	  color-scheme: light;
3	  --blue-950: #06164a;
4	  --blue-900: #09266f;
5	  --blue-800: #0a3fb8;
6	  --blue-700: #075bec;
7	  --blue-500: #168cff;
8	  --blue-100: #eaf3ff;
9	  --cyan: #30d8ff;
10	  --ink: #07163e;
11	  --muted: #53668d;
12	  --line: rgba(34, 107, 230, 0.22);
13	  --line-strong: rgba(24, 92, 218, 0.42);
14	  --glass: rgba(255, 255, 255, 0.72);
15	  --glass-strong: rgba(255, 255, 255, 0.9);
16	  --shadow: 0 18px 44px rgba(11, 57, 150, 0.16);
17	}
18	
19	* {
20	  box-sizing: border-box;
21	}
22	
23	html {
24	  min-width: 320px;
25	  background: #eef6ff;
26	}
27	
28	body {
29	  margin: 0;
30	  min-height: 100vh;
31	  overflow: hidden;
32	  background:
33	    radial-gradient(circle at 50% 0%, rgba(255, 255, 255, 0.95) 0 24%, transparent 46%),
34	    linear-gradient(115deg, rgba(18, 119, 255, 0.08), transparent 38%),
35	    linear-gradient(245deg, rgba(18, 119, 255, 0.1), transparent 42%),
36	    #eef6ff;
37	  color: var(--ink);
38	  font-family:
39	    "Arial Narrow", "PingFang SC", "Microsoft YaHei", Inter, ui-sans-serif,
40	    system-ui, sans-serif;
41	  letter-spacing: 0;
42	}
43	
44	button,
45	a,
46	input,
47	textarea {
48	  font: inherit;
49	}
50	
51	button {
52	  cursor: pointer;
53	}
54	
55	h1,
56	h2,
57	h3,
58	p {
59	  margin-top: 0;
60	}
61	
62	.deck-shell {
63	  width: min(100vw, 1920px);
64	  height: min(100vh, 1080px);
65	  margin: 0 auto;
66	  padding: 26px 32px 24px;
67	  position: relative;
68	  overflow: hidden;
69	}
70	
71	.deck-shell::before,
72	.deck-shell::after {
73	  content: "";
74	  position: absolute;
75	  inset: 112px -60px auto;
76	  height: 760px;
77	  pointer-events: none;
78	  background:
79	    linear-gradient(105deg, transparent 0 18%, rgba(42, 157, 255, 0.18) 19%, transparent 24% 100%),
80	    repeating-linear-gradient(164deg, transparent 0 26px, rgba(25, 110, 255, 0.1) 27px 29px, transparent 30px 74px);
81	  transform: skewY(-6deg);
82	  opacity: 0.82;
83	}
84	
85	.deck-shell::after {
86	  inset: auto -80px -170px;
87	  height: 440px;
88	  background:
89	    linear-gradient(100deg, transparent, rgba(19, 137, 255, 0.35), transparent),
90	    repeating-linear-gradient(172deg, transparent 0 32px, rgba(25, 110, 255, 0.18) 33px 36px, transparent 37px 88px);
91	  transform: skewY(-4deg);
92	  opacity: 0.74;
93	}
94	
95	.deck-header {
96	  position: relative;
97	  z-index: 10;
98	  display: grid;
99	  grid-template-columns: 430px minmax(0, 1fr) 120px;
100	  gap: 28px;
101	  align-items: center;
102	  height: 68px;
103	}
104	
105	.brand {
106	  display: inline-flex;
107	  align-items: center;
108	  gap: 12px;
109	  min-width: 0;
110	  text-decoration: none;
111	  color: var(--blue-950);
112	}
113	
114	.brand-emblem {
