116	  place-items: center;
117	  width: 62px;
118	  height: 68px;
119	  border: 0;
120	  background: transparent;
121	  box-shadow: none;
122	}
123	
124	.brand-emblem img {
125	  width: 62px;
126	  height: 68px;
127	  display: block;
128	  object-fit: contain;
129	}
130	
131	.brand strong {
132	  display: block;
133	  font-size: 28px;
134	  font-style: italic;
135	  font-weight: 950;
136	  line-height: 0.98;
137	}
138	
139	.brand small {
