809	function resizeCanvas(canvas) {
810	  const rect = canvas.getBoundingClientRect();
811	  const scale = window.devicePixelRatio || 1;
812	  canvas.width = Math.max(1, Math.floor(rect.width * scale));
813	  canvas.height = Math.max(1, Math.floor(rect.height * scale));
814	  canvas.getContext("2d").setTransform(scale, 0, 0, scale, 0, 0);
815	}
816	
817	function resizeAll() {
