821	function racePoint(progress, lane, width, height, theme) {
822	  const yBase = theme === "home" ? 0.63 : 0.55;
823	  return {
824	    x: width * (0.06 + progress * 0.88),
825	    y:
826	      height *
827	      (yBase +
828	        Math.sin(progress * Math.PI * 2.8 + lane * 3.6) * 0.16 +
829	        Math.cos(progress * Math.PI * 1.35) * 0.08 +
830	        (lane - 0.5) * 0.18),
831	  };
832	}
