834	function drawSpeedLines(ctx, width, height, dark) {
835	  ctx.save();
836	  ctx.globalAlpha = dark ? 0.42 : 0.3;
837	  for (let i = 0; i < 34; i += 1) {
838	    const y = height * (0.12 + i * 0.026);
839	    const start = -width * 0.12 + i * 17;
840	    const end = width * (0.92 + (i % 6) * 0.02);
841	    const gradient = ctx.createLinearGradient(start, y, end, y - 60);
842	    gradient.addColorStop(0, "rgba(22,140,255,0)");
843	    gradient.addColorStop(0.45, dark ? "rgba(48,216,255,0.42)" : "rgba(22,140,255,0.26)");
844	    gradient.addColorStop(1, "rgba(22,140,255,0)");
845	    ctx.strokeStyle = gradient;
846	    ctx.lineWidth = i % 5 === 0 ? 5 : 2;
847	    ctx.beginPath();
848	    ctx.moveTo(start, y);
849	    ctx.lineTo(end, y - height * 0.22);
850	    ctx.stroke();
851	  }
852	  ctx.restore();
853	}
