855	function drawBackground(ctx, width, height, theme) {
856	  const dark = theme === "screen";
857	  ctx.clearRect(0, 0, width, height);
858	  const bg = ctx.createLinearGradient(0, 0, width, height);
859	  bg.addColorStop(0, dark ? "#06164a" : "#ffffff");
860	  bg.addColorStop(0.55, dark ? "#08215f" : "#eef7ff");
861	  bg.addColorStop(1, dark ? "#02091e" : "#dcecff");
862	  ctx.fillStyle = bg;
863	  ctx.fillRect(0, 0, width, height);
864	  drawSpeedLines(ctx, width, height, dark);
865	
866	  const horizon = dark ? height * 0.7 : height * 0.62;
867	  ctx.strokeStyle = dark ? "rgba(255,255,255,0.16)" : "rgba(7,91,236,0.18)";
868	  ctx.lineWidth = 2;
869	  for (let i = 0; i < 10; i += 1) {
870	    ctx.beginPath();
871	    ctx.moveTo(width * 0.04, horizon + i * 18);
872	    ctx.quadraticCurveTo(width * 0.52, horizon - 110 + i * 6, width * 0.96, horizon + i * 22);
873	    ctx.stroke();
874	  }
875	}
