877	function drawTrack(ctx, width, height, theme) {
878	  const dark = theme === "screen";
879	  ctx.strokeStyle = dark ? "rgba(48,216,255,0.72)" : "rgba(7,91,236,0.52)";
880	  ctx.lineWidth = theme === "screen" ? 6 : 4;
881	  ctx.beginPath();
882	  ctx.moveTo(width * 0.08, height * 0.82);
883	  ctx.bezierCurveTo(width * 0.24, height * 0.22, width * 0.48, height * 0.86, width * 0.68, height * 0.42);
884	  ctx.bezierCurveTo(width * 0.78, height * 0.22, width * 0.88, height * 0.44, width * 0.95, height * 0.26);
885	  ctx.stroke();
886	}
