888	function drawRiderMarker(ctx, rider, width, height, time, theme, index) {
889	  const dark = theme === "screen";
890	  const progress = (rider.phase + time * rider.speed) % 1;
891	  const point = racePoint(progress, rider.lane, width, height, theme);
892	  const tail = racePoint(Math.max(0, progress - 0.09), rider.lane, width, height, theme);
893	  const radius = theme === "screen" ? 16 : 11;
894	  const trail = ctx.createLinearGradient(tail.x, tail.y, point.x, point.y);
895	  trail.addColorStop(0, "rgba(255,255,255,0)");
896	  trail.addColorStop(1, rider.color);
897	  ctx.strokeStyle = trail;
898	  ctx.lineWidth = theme === "screen" ? 8 : 5;
899	  ctx.beginPath();
900	  ctx.moveTo(tail.x, tail.y);
901	  ctx.lineTo(point.x, point.y);
902	  ctx.stroke();
903	  ctx.fillStyle = "rgba(255,255,255,0.95)";
904	  ctx.beginPath();
905	  ctx.arc(point.x, point.y, radius, 0, Math.PI * 2);
906	  ctx.fill();
907	  ctx.strokeStyle = rider.color;
908	  ctx.lineWidth = 5;
909	  ctx.stroke();
910	  ctx.fillStyle = dark ? "#ffffff" : "#06164a";
911	  ctx.font = `950 ${theme === "screen" ? 24 : 15}px Arial, sans-serif`;
912	  ctx.fillText(rider.name, point.x + radius + 8, point.y - radius - index);
913	}
