915	function drawOverlay(ctx, width, height, time, theme) {
916	  const dark = theme === "screen";
917	  const signal = Math.round((getRace(sampleData.raceGroups.featuredRaceId)?.live?.ridingSignal || 75) + Math.sin(time / 560) * 4);
918	  const cardX = theme === "home" ? 28 : 24;
919	  const cardY = theme === "home" ? 36 : 24;
920	  const labelY = cardY + (theme === "screen" ? 34 : 26);
921	  const valueY = cardY + (theme === "screen" ? 80 : 59);
922	  ctx.fillStyle = dark ? "rgba(255,255,255,0.12)" : "rgba(255,255,255,0.82)";
923	  ctx.strokeStyle = dark ? "rgba(255,255,255,0.24)" : "rgba(7,91,236,0.22)";
924	  ctx.lineWidth = 2;
925	  ctx.beginPath();
926	  ctx.roundRect(cardX, cardY, theme === "screen" ? 270 : 180, theme === "screen" ? 112 : 78, 4);
927	  ctx.fill();
928	  ctx.stroke();
929	  ctx.fillStyle = dark ? "#bfe3ff" : "#075bec";
930	  ctx.font = `950 ${theme === "screen" ? 15 : 12}px Arial, sans-serif`;
931	  ctx.fillText("RIDING SIGNAL", cardX + 18, labelY);
932	  ctx.fillStyle = dark ? "#ffffff" : "#075bec";
933	  ctx.font = `950 italic ${theme === "screen" ? 48 : 30}px Arial, sans-serif`;
934	  ctx.fillText(`${signal}%`, cardX + 18, valueY);
