938	function drawFrame(time) {
939	  canvases.forEach(({ node, theme }) => {
940	    const rect = node.getBoundingClientRect();
941	    if (rect.width < 1 || rect.height < 1) return;
942	    const ctx = node.getContext("2d");
943	    drawBackground(ctx, rect.width, rect.height, theme);
944	    drawTrack(ctx, rect.width, rect.height, theme);
945	    riders.forEach((rider, index) => drawRiderMarker(ctx, rider, rect.width, rect.height, time, theme, index));
946	    drawOverlay(ctx, rect.width, rect.height, time, theme);
947	  });
948	  requestAnimationFrame(drawFrame);
949	}
