953	    this.moveTo(x + radius, y);
954	    this.lineTo(x + width - radius, y);
955	    this.quadraticCurveTo(x + width, y, x + width, y + radius);
956	    this.lineTo(x + width, y + height - radius);
957	    this.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
958	    this.lineTo(x + radius, y + height);
959	    this.quadraticCurveTo(x, y + height, x, y + height - radius);
960	    this.lineTo(x, y + radius);
961	    this.quadraticCurveTo(x, y, x + radius, y);
962	    return this;
963	  };
